const { DynamoDBClient, UpdateItemCommand } = require("@aws-sdk/client-dynamodb");

const ddb = new DynamoDBClient({});

const ORDERS_TABLE = process.env.ORDERS_TABLE;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const PAYMENT_API_KEY = process.env.PAYMENT_API_KEY;
const PAYMENT_TIMEOUT_MS = Number(process.env.PAYMENT_TIMEOUT_MS || 5000);

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function toStr(val) {
  if (val == null) return "";
  return typeof val === "string" ? val : String(val);
}

async function callPaymentApi({ orderId, amount, currency, paymentMethod, customerId }) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), PAYMENT_TIMEOUT_MS);

  try {
    const res = await fetch(`${PAYMENT_API_URL}/charge`, {
      method: "POST",
      headers: {
        "content-type": "application/json",
        authorization: PAYMENT_API_KEY ? `Bearer ${PAYMENT_API_KEY}` : undefined,
      },
      body: JSON.stringify({
        orderId,
        amount,
        currency,
        paymentMethod,
        customerId,
      }),
      signal: controller.signal,
    });

    const text = await res.text();
    let data;
    try {
      data = text ? JSON.parse(text) : {};
    } catch {
      data = { raw: text };
    }

    if (!res.ok) {
      const err = new Error(`Payment API error: ${res.status}`);
      err.status = res.status;
      err.body = data;
      throw err;
    }

    return data;
  } finally {
    clearTimeout(timeout);
  }
}

async function updateOrderStatus({ orderId, status, paymentId, errorMessage }) {
  if (!ORDERS_TABLE) throw new Error("ORDERS_TABLE env var is required");
  if (!orderId) throw new Error("orderId is required");

  const exprNames = {
    "#s": "status",
    "#u": "updatedAt",
  };

  const exprValues = {
    ":s": { S: toStr(status) },
    ":u": { N: String(Date.now()) },
  };

  let updateExpr = "SET #s = :s, #u = :u";

  if (paymentId) {
    exprNames["#p"] = "paymentId";
    exprValues[":p"] = { S: toStr(paymentId) };
    updateExpr += ", #p = :p";
  }

  if (errorMessage) {
    exprNames["#e"] = "errorMessage";
    exprValues[":e"] = { S: toStr(errorMessage).slice(0, 1024) };
    updateExpr += ", #e = :e";
  }

  await ddb.send(
    new UpdateItemCommand({
      TableName: ORDERS_TABLE,
      Key: { orderId: { S: toStr(orderId) } },
      UpdateExpression: updateExpr,
      ExpressionAttributeNames: exprNames,
      ExpressionAttributeValues: exprValues,
    })
  );
}

async function processRecord(record) {
  let payload;
  try {
    payload = JSON.parse(record.body || "{}");
  } catch (e) {
    console.error("Invalid JSON in SQS message body", { messageId: record.messageId, body: record.body, error: e });
    return;
  }

  const orderId = payload.orderId || payload.id;
  const amount = payload.amount;
  const currency = payload.currency || "USD";
  const paymentMethod = payload.paymentMethod;
  const customerId = payload.customerId;

  if (!orderId) {
    console.error("Missing orderId", { messageId: record.messageId, payload });
    return;
  }

  try {
    await updateOrderStatus({ orderId, status: "PROCESSING" });
  } catch (e) {
    console.error("Failed to mark order PROCESSING", { orderId, error: e });
  }

  try {
    const paymentRes = await callPaymentApi({ orderId, amount, currency, paymentMethod, customerId });
    const paymentId = paymentRes.paymentId || paymentRes.id || "";
    await updateOrderStatus({ orderId, status: "PAID", paymentId });
  } catch (e) {
    console.error("Payment failed", { orderId, error: e, details: { status: e.status, body: e.body } });
    try {
      await updateOrderStatus({ orderId, status: "PAYMENT_FAILED", errorMessage: e.message });
    } catch (ee) {
      console.error("Failed to mark order PAYMENT_FAILED", { orderId, error: ee });
    }
  }
}

exports.handler = async (event) => {
  const records = Array.isArray(event.Records) ? event.Records : [];
  const concurrency = Math.max(1, Number(process.env.CONCURRENCY || 10));

  let idx = 0;
  const workers = Array.from({ length: Math.min(concurrency, records.length || 1) }, async () => {
    while (true) {
      const i = idx++;
      if (i >= records.length) return;
      const record = records[i];

      try {
        await processRecord(record);
      } catch (e) {
        console.error("Unexpected error processing record", { messageId: record.messageId, error: e });
        await sleep(0);
      }
    }
  });

  await Promise.all(workers);
};